- Last year refers to the year 2022;
- Each scientist refers to each researcher.

sql:
SELECT parameter_id, simulation_id, ecut, nkpts, alat
FROM simulation_parameters
WHERE optimizer = 'Conjugate Gradient';

external_knowledge:
- 'original team' refers to the research group with ID 0;
- 'successful simulations' denote those with a 'completed' status;
- 'key force metrics' include the total force and energy values;
- 'energy levels from the highest to the lowest' implies sorting in descending order by the energy column.

- "captains" refers to researchers;
- "navigated their voyages" is a metaphor for completing simulations;
- "key to the treasure room" symbolizes having the 'admin' role.

sql:
SELECT AVG(energy) AS Average_Energy
FROM simulations
WHERE research_group_id = 1;

SELECT COUNT(*) 
FROM simulations 
WHERE researcher_id = (SELECT researcher_id FROM simulations WHERE filename = 'simulation1.txt');

SELECT researchers.researcher_name, simulations.simulation_status
FROM researchers
INNER JOIN simulations ON researchers.researcher_id = simulations.researcher_id;
